import{_ as a,o as s,c as e,a2 as n}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"算法公开","description":"","frontmatter":{},"headers":[],"relativePath":"guide/suanfa.md","filePath":"guide/suanfa.md","lastUpdated":null}'),d={name:"guide/suanfa.md"};function i(r,t,l,p,h,o){return s(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="算法公开" tabindex="-1">算法公开 <a class="header-anchor" href="#算法公开" aria-label="Permalink to &quot;算法公开&quot;">​</a></h1><p>本文档公开服务器所有核心算法的计算公式，帮助玩家精确规划修仙路线。</p><hr><h2 id="一、突破成功率" tabindex="-1">一、突破成功率 <a class="header-anchor" href="#一、突破成功率" aria-label="Permalink to &quot;一、突破成功率&quot;">​</a></h2><h3 id="小阶突破" tabindex="-1">小阶突破 <a class="header-anchor" href="#小阶突破" aria-label="Permalink to &quot;小阶突破&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础成功率 = 0.5（全局基础） × 境界小阶突破成功率</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最终成功率 = 基础成功率</span></span>
<span class="line"><span>            + 灵根突破加成</span></span>
<span class="line"><span>            + 突破丹效果值</span></span>
<span class="line"><span>            + 天道境界突破加成</span></span>
<span class="line"><span>            + 天道试炼事件加成（若激活）</span></span>
<span class="line"><span>            + 连续失败保护（若触发）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>各境界小阶成功率（来自 <code>修仙境界.json</code>）：</p><table tabindex="0"><thead><tr><th>境界</th><th>小阶成功率</th><th>叠加基础(0.5)后</th></tr></thead><tbody><tr><td>练气</td><td>75%</td><td>37.5%</td></tr><tr><td>筑基</td><td>65%</td><td>32.5%</td></tr><tr><td>金丹</td><td>55%</td><td>27.5%</td></tr><tr><td>元婴</td><td>45%</td><td>22.5%</td></tr><tr><td>化神</td><td>38%</td><td>19.0%</td></tr><tr><td>渡劫</td><td>30%</td><td>15.0%</td></tr><tr><td>大乘</td><td>25%</td><td>12.5%</td></tr><tr><td>飞升</td><td>18%</td><td>9.0%</td></tr></tbody></table><h3 id="大境界突破" tabindex="-1">大境界突破 <a class="header-anchor" href="#大境界突破" aria-label="Permalink to &quot;大境界突破&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础成功率 = 0.25（全局基础） × 境界大境界突破成功率</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最终成功率 = 基础成功率 + 同上各项加成</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>各境界大境界成功率：</p><table tabindex="0"><thead><tr><th>境界</th><th>大境界成功率</th><th>叠加基础(0.25)后</th></tr></thead><tbody><tr><td>练气→筑基</td><td>45%</td><td>11.25%</td></tr><tr><td>筑基→金丹</td><td>40%</td><td>10.0%</td></tr><tr><td>金丹→元婴</td><td>30%</td><td>7.5%</td></tr><tr><td>元婴→化神</td><td>25%</td><td>6.25%</td></tr><tr><td>化神→渡劫</td><td>20%</td><td>5.0%</td></tr><tr><td>渡劫→大乘</td><td>15%</td><td>3.75%</td></tr><tr><td>大乘→飞升</td><td>12%</td><td>3.0%</td></tr></tbody></table><h3 id="突破成功率计算示例" tabindex="-1">突破成功率计算示例 <a class="header-anchor" href="#突破成功率计算示例" aria-label="Permalink to &quot;突破成功率计算示例&quot;">​</a></h3><p><strong>场景</strong>：天灵根（+20%）修士在化神9阶，使用极品突破丹（+65%），天道境界为「代天行道」（+8%），突破到大乘期。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础成功率 = 0.25 × 0.12 = 3.0%</span></span>
<span class="line"><span>灵根加成  = +20.0%</span></span>
<span class="line"><span>突破丹    = +65.0%</span></span>
<span class="line"><span>天道加成  = +8.0%</span></span>
<span class="line"><span>─────────────────────</span></span>
<span class="line"><span>最终成功率 = 3.0 + 20 + 65 + 8 = 96.0%</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="突破成本" tabindex="-1">突破成本 <a class="header-anchor" href="#突破成本" aria-label="Permalink to &quot;突破成本&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>突破灵气消耗 = 当前灵气 × 境界突破消耗比例</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><table tabindex="0"><thead><tr><th>境界</th><th>消耗比例</th></tr></thead><tbody><tr><td>练气</td><td>70%</td></tr><tr><td>筑基</td><td>75%</td></tr><tr><td>金丹</td><td>80%</td></tr><tr><td>元婴</td><td>82%</td></tr><tr><td>化神</td><td>85%</td></tr><tr><td>渡劫</td><td>88%</td></tr><tr><td>大乘</td><td>90%</td></tr><tr><td>飞升</td><td>95%</td></tr></tbody></table><hr><h2 id="二、渡劫计算" tabindex="-1">二、渡劫计算 <a class="header-anchor" href="#二、渡劫计算" aria-label="Permalink to &quot;二、渡劫计算&quot;">​</a></h2><h3 id="天雷伤害" tabindex="-1">天雷伤害 <a class="header-anchor" href="#天雷伤害" aria-label="Permalink to &quot;天雷伤害&quot;">​</a></h3><p>渡劫时每道天雷造成的伤害由境界配置决定：</p><table tabindex="0"><thead><tr><th>境界</th><th>天雷道数</th><th>每道伤害</th><th>间隔</th></tr></thead><tbody><tr><td>金丹</td><td>3道</td><td>30</td><td>2.5秒</td></tr><tr><td>元婴</td><td>6道</td><td>60</td><td>2.5秒</td></tr><tr><td>化神</td><td>9道</td><td>100</td><td>2.0秒</td></tr><tr><td>渡劫</td><td>12道</td><td>160</td><td>2.0秒</td></tr><tr><td>大乘</td><td>15道</td><td>250</td><td>1.5秒</td></tr><tr><td>飞升</td><td>18道</td><td>400</td><td>1.5秒</td></tr></tbody></table><h3 id="渡劫减伤" tabindex="-1">渡劫减伤 <a class="header-anchor" href="#渡劫减伤" aria-label="Permalink to &quot;渡劫减伤&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实际天雷伤害 = 基础天雷伤害 × (1 - 天道渡劫减伤)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><table tabindex="0"><thead><tr><th>天道境界</th><th>减伤</th></tr></thead><tbody><tr><td>普通人</td><td>0%</td></tr><tr><td>有德</td><td>0%</td></tr><tr><td>积善</td><td>10%</td></tr><tr><td>天道眷顾</td><td>20%</td></tr><tr><td>代天行道</td><td>30%</td></tr><tr><td>天人合一</td><td>40%</td></tr></tbody></table><p><strong>示例</strong>：天人合一修士渡飞升劫 → 400 × (1 - 0.4) = <strong>240伤害/道</strong>（18道共 4,320 总伤害）</p><h3 id="渡劫失败" tabindex="-1">渡劫失败 <a class="header-anchor" href="#渡劫失败" aria-label="Permalink to &quot;渡劫失败&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>渡劫失败扣血 = 150（固定）</span></span>
<span class="line"><span>渡劫掉落物品 = true（可能损失道具）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="三、炼丹成功率" tabindex="-1">三、炼丹成功率 <a class="header-anchor" href="#三、炼丹成功率" aria-label="Permalink to &quot;三、炼丹成功率&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>丹药炼制成功率 = 丹药品质基础成功率 + 修仙等级 × 1%</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><table tabindex="0"><thead><tr><th>修仙等级</th><th>下阶突破丹(70%)</th><th>极品渡劫丹(20%)</th></tr></thead><tbody><tr><td>等级10</td><td>80%</td><td>30%</td></tr><tr><td>等级30</td><td>100%</td><td>50%</td></tr><tr><td>等级50</td><td>100%（封顶）</td><td>70%</td></tr><tr><td>等级80</td><td>100%</td><td>100%（封顶）</td></tr></tbody></table><h3 id="炼丹失败伤害" tabindex="-1">炼丹失败伤害 <a class="header-anchor" href="#炼丹失败伤害" aria-label="Permalink to &quot;炼丹失败伤害&quot;">​</a></h3><table tabindex="0"><thead><tr><th>品质</th><th>突破丹</th><th>渡劫丹</th><th>治疗丹</th><th>恢复丹</th></tr></thead><tbody><tr><td>下阶</td><td>0</td><td>0</td><td>0</td><td>0</td></tr><tr><td>中等</td><td>0</td><td>0</td><td>0</td><td>0</td></tr><tr><td>高级</td><td>30</td><td>35</td><td>25</td><td>28</td></tr><tr><td>极品</td><td>80</td><td>100</td><td>60</td><td>70</td></tr></tbody></table><blockquote><p>⚠️ 极品渡劫丹失败直接扣100血！务必在满血状态下炼制。</p></blockquote><hr><h2 id="四、功法威力计算" tabindex="-1">四、功法威力计算 <a class="header-anchor" href="#四、功法威力计算" aria-label="Permalink to &quot;四、功法威力计算&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实际伤害 = 功法基础伤害 × 威力倍率 × 灵根契合倍率 × 天灵根全功法倍率</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="灵根契合倍率" tabindex="-1">灵根契合倍率 <a class="header-anchor" href="#灵根契合倍率" aria-label="Permalink to &quot;灵根契合倍率&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>倍率</th></tr></thead><tbody><tr><td>灵根 ≠ 功法契合灵根</td><td>×1.0</td></tr><tr><td>灵根 = 功法契合灵根</td><td>×1.5</td></tr><tr><td>天灵根所有功法</td><td>×1.2</td></tr><tr><td>天灵根 + 同灵根功法</td><td>×1.5 × 1.2 = ×1.8</td></tr></tbody></table><p><strong>示例</strong>：天灵根修士释放「飞升羽化」（天灵根契合）：</p><ul><li>同灵根 ×1.5 + 所有功法 ×1.2 = <strong>×1.8 倍率</strong></li></ul><hr><h2 id="五、防御减伤" tabindex="-1">五、防御减伤 <a class="header-anchor" href="#五、防御减伤" aria-label="Permalink to &quot;五、防御减伤&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最终防御 = 基础防御 × 灵根防御倍率 + 功法/Buff额外防御 + 每小阶防御加成</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>土灵根防御 ×1.15</li><li>天灵根防御 ×1.1</li><li>每小阶 +1 防御</li></ul><hr><h2 id="六、速度计算" tabindex="-1">六、速度计算 <a class="header-anchor" href="#六、速度计算" aria-label="Permalink to &quot;六、速度计算&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实际速度 = 基础速度 × Π(每大境界速度倍率) × 灵根无额外倍率</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>每突破1个大境界，速度 ×1.02：</p><ul><li>练气 → 飞升（8次大突破）：速度 × 1.02⁸ = <strong>×1.172</strong></li></ul><hr><h2 id="七、吸血公式" tabindex="-1">七、吸血公式 <a class="header-anchor" href="#七、吸血公式" aria-label="Permalink to &quot;七、吸血公式&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>怪物吸血量 = 造成伤害 × 吸血比率</span></span>
<span class="line"><span>最终吸血量 = min(吸血量, 怪物基础HP × 1.5)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><table tabindex="0"><thead><tr><th>类型</th><th>吸血比率</th><th>上限倍率</th></tr></thead><tbody><tr><td>普通怪物</td><td>20%</td><td>×1.5</td></tr><tr><td>Boss</td><td>35%</td><td>×1.5</td></tr></tbody></table><hr><h2 id="八、boss动态缩放" tabindex="-1">八、Boss动态缩放 <a class="header-anchor" href="#八、boss动态缩放" aria-label="Permalink to &quot;八、Boss动态缩放&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实际HP  = Boss基础HP  × (1 + 修士修仙等级 × 0.05)</span></span>
<span class="line"><span>实际伤害 = Boss基础伤害 × (1 + 修士修仙等级 × 0.05)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>示例</strong>：修仙等级 50 的修士挑战克苏鲁之眼（基础HP 2800）：</p><ul><li>实际HP = 2800 × (1 + 50 × 0.05) = 2800 × 3.5 = <strong>9,800 HP</strong></li></ul><p>受缩放的Boss完整列表见 <a href="/guide/boss.html">Boss战斗</a> 页面。</p><hr><h2 id="九、修炼效率公式" tabindex="-1">九、修炼效率公式 <a class="header-anchor" href="#九、修炼效率公式" aria-label="Permalink to &quot;九、修炼效率公式&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每秒修为 = 修炼消耗灵气(5.0) × 灵气转修为比例(0.12) = 0.6</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每秒灵气净变化 = 灵气恢复 - 修炼消耗(5.0)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>灵气恢复不足时无法持续修炼，需要等待自然恢复或使用恢复丹。</p><h3 id="灵气潮汐期间" tabindex="-1">灵气潮汐期间 <a class="header-anchor" href="#灵气潮汐期间" aria-label="Permalink to &quot;灵气潮汐期间&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>修炼每秒修为 = 0.6 × 1.5 = 0.9</span></span>
<span class="line"><span>灵力恢复 × 2.0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="十、功德衰减" tabindex="-1">十、功德衰减 <a class="header-anchor" href="#十、功德衰减" aria-label="Permalink to &quot;十、功德衰减&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每日衰减 = 当前功德 × 5%（不活跃7天后触发）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>例如：1000功德，不活跃7天后：</p><ul><li>第8天：1000 - 50 = 950</li><li>第9天：950 - 47.5 = 902.5</li><li>以此类推...</li></ul><hr><h2 id="十一、决斗死亡惩罚" tabindex="-1">十一、决斗死亡惩罚 <a class="header-anchor" href="#十一、决斗死亡惩罚" aria-label="Permalink to &quot;十一、决斗死亡惩罚&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>决斗失败扣灵气 = 当前灵气 × 20%</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>比普通死亡的25%略低，但仍有不小代价。</p>`,77)])])}const u=a(d,[["render",i]]);export{c as __pageData,u as default};
